var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"신이시여.","JPN":"神よ。","ENG":"When I am called to duty, God.","TWN":"神哪。"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CAT_IN_TRAILER_1"},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"제가 부름을 받을 때에는.","JPN":"私が呼び出されたときには、","ENG":"Wherever flames may rage.","TWN":"當我執行勤務時，"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CAT_IN_TRAILER_2"},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"아무리 맹렬한 화염속에서도.","JPN":"たとえ業火の中であろうと、","ENG":"Give me the strength to save a life.","TWN":" 儘管火焰總是那麼猛烈，"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CAT_IN_TRAILER_3"},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"한 생명을 구할 수 있는 힘을 저에게 주소서.","JPN":"尊い命を救うための、強靭な力を与え給え。","ENG":"Whatever by its age.","TWN":"請賜給我力量去拯救生命。"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CAT_IN_TRAILER_4"},{"id":"L9_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"제안. 포기하십시오.","JPN":"提案。諦めてください。","ENG":"Suggestion. Give up.","TWN":"提議。放棄。"},"stage":{"bg":"SPACE_GRAVITY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"바이탈 체크. 이미 침식 증후군 증세를 보이고 있습니다.","JPN":"バイタルチェック。すでに侵食症候群の症状が現れています。","ENG":"Checking vital signs. You are already showing signs of Corruption Syndrome.","TWN":"確認生命跡象。你已出現了侵蝕症候群的跡象。"},"stage":{"bg":"SPACE_GRAVITY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"시끄러워……!!","JPN":"うるさい……！！","ENG":"Shut up...!!","TWN":"閉嘴……！！"},"stage":{"bg":"SPACE_GRAVITY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"여기서 너희를 막지 않으면, 또 쓸데없는 이유로 수많은 사람을 죽일 거잖아!","JPN":"ここでおまえらを止めないと、またくだらない理由でたくさんの人が死ぬことになる！","ENG":"If I don't stop you here, you're going to kill more people for your stupid reasons!","TWN":"如果不在這裡阻止你們，又會有許多無辜的人因你們而喪命！"},"stage":{"bg":"SPACE_GRAVITY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"부정. 쓸데없지 않습니다.","JPN":"否定。くだらなくはありません。","ENG":"Negative. It is not stupid.","TWN":"否定。這毫無用處。"},"stage":{"bg":"SPACE_GRAVITY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"냉동수면이 유지되는 동안, 인간. 자신이 바라는 세계에서 바라는 삶을 살게 됩니다.","JPN":"冷凍保存が維持されている間、人間は理想の世界で理想の人生を歩むことができます。","ENG":"While you are in cryogenic sleep, human, you will live in the world you always wanted.","TWN":"冷凍休眠期間，你會在你想要的世界裡過你想要的生活。人類。"},"stage":{"bg":"SPACE_GRAVITY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"연합의 인류 대부분 스스로 보존되는 걸 택했습니다.","JPN":"連合のほとんどの人類は、自ら保存されることを選びました。","ENG":"Most of the humans in the Interstellar Alliance have already chosen preservation.","TWN":"聯盟的大部分人類選擇了保存。"},"stage":{"bg":"SPACE_GRAVITY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"육체가 아닌, 정신의 자유. 그것이 연합이 선택한 최선의 선택.","JPN":"肉体ではなく、精神の自由。それこそ、連合が選んだ最善の選択。","ENG":"A freedom of mind, not the body. That is the Interstellar Alliance's best choice.","TWN":"心靈的自由，不是身體的自由。這對聯盟來說是最好的選擇。"},"stage":{"bg":"SPACE_GRAVITY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"인류가 멸망을 피할 수 있는 유일한 방법입니다.","JPN":"人類が滅亡を避けられる唯一の方法です。","ENG":"It is the only way to avoid humanity's destruction.","TWN":"這是人類避免毀滅的唯一途徑。"},"stage":{"bg":"SPACE_GRAVITY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"제 소명을 수행케 하시고.","JPN":"私が天職に従い。","ENG":"I want to fill my calling,","TWN":"請讓我履行使命。"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CAT_IN_TRAILER_5"},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"언제나 최선을 다할 수 있게 도와주시옵소서.","JPN":"いつでも全力を出せるよう、私をお助けください。","ENG":"and give the best in me.","TWN":"幫助我盡力而為。"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CAT_IN_TRAILER_6"},{"id":"L27_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"웃기지 마……!! 그딴 게 최선이라고……!?","JPN":"ふざけるな……！！　それが最善だって……！？","ENG":"Don't make me laugh...! That's the best choice...?!","TWN":"開什麼玩笑……！！這就是最好的了……？！"},"stage":{"bg":"SPACE_GRAVITY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그건 그냥 도망친 것뿐이잖아……!!","JPN":"それはただ逃げただけじゃないか……！！","ENG":"That's just running away...!!","TWN":"這不就是逃跑嗎……！！"},"stage":{"bg":"SPACE_GRAVITY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"나에게 있어서 최선이라는 건……!!","JPN":"アタシにとって最善ってのは……！！","ENG":"The best choice for me is...!","TWN":"對我來說最好的選擇是……！！"},"stage":{"bg":"SPACE_GRAVITY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"훌륭한 소방관이라면, 구조자의 목숨과 자신의 목숨……. 어느 쪽도 놓치지 않는다.","JPN":"立派な消防士なら、救助者の命と自分の命……どっちも取りこぼさない。","ENG":"An excellent firefighter knows how to save both... the rescuee's and the rescuer's lives.","TWN":"一名優秀的消防員，求救者和自己的生命……任何一方都不能放棄。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L31_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"마지막까지 최선을 다하되, 자기 목숨까지 버리지는 말아라.","JPN":"最後までベストを尽くせ。だが、自分の命も守るんだ。","ENG":"I'm telling you to do your best until the very end, but not throw away your own life.","TWN":"竭盡我們最大的努力，但不許把自己的命也賠進去！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"그 화재로 동료분들을 잃으셨다고 들었어요.","JPN":"あの火災で同僚の方々が亡くなられたと聞きました。","ENG":"I heard you lost a lot of colleagues to that fire.","TWN":"我聽說你在那場火災中失去了很多同事。"},"stage":{"bg":"FALL_PARK","bgm":null,"filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"하지만 최선을 다하셨는데, 그렇게까지 자책하실 필요는 없다고 생각해요.","JPN":"でも、ベストを尽くしたのにそこまで自分を責める必要はないと思います。","ENG":"But you did your best, so there's no need to keep blaming yourself.","TWN":"但你已經盡力了，我認為你不必太自責。"},"stage":{"bg":"FALL_PARK","bgm":null,"filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"네가 관리국에…… 그리고 야크샤에게 반드시 필요한 사람이었기 때문이었어.","JPN":"あなたが管理局に……そしてヤクシャーに必ず必要な人間だったからよ。","ENG":"It was because... you were someone the Administration and Yaksha needed.","TWN":"你對於管理局……對於夜叉來說，都是不可缺少的存在。"},"stage":{"bg":"OFFICE_TOP","bgm":null,"filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L36_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그래서 우린 그 화재에서 너를 선택한 거야.","JPN":"だから私たちは、あの火災であなたを選択したの。","ENG":"That's why we chose you in that fire.","TWN":"這就是為什麼我們在那場大火中選擇了你。"},"stage":{"bg":"OFFICE_TOP","bgm":null,"filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그게 우리의 최선이었어.","JPN":"それが私たちにとっての最善だった。","ENG":"That was our best outcome.","TWN":"那是我們最好的結果。"},"stage":{"bg":"OFFICE_TOP","bgm":null,"filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"고민하고, 결심하고, 상처입고, 극복하고, 다짐하고, 좌절하고, 다시 일어서고……!","JPN":"悩んで、決意して、傷ついて、乗り越えて、誓って、挫折して、また立ち上がって……！","ENG":"After thinking, deciding, getting hurt, overcoming, promising, being discouraged, and getting back up...!","TWN":"我思考過、決定過、受傷過、克服過、承諾過、沮喪過，也重新站起來過……！"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"최후의 최후까지 할 수 있는 건 전부 다 해본 뒤에 내리는 마지막 선택이야!","JPN":"最後の最後まで、ギリギリまでやれることを全部やってから決めることだ！","ENG":"After doing everything that I could until the very end, this is the choice I made!","TWN":"這是我拼盡全力直到最後才做出的選擇！"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그 끝에 어떤 결말이 기다리고 있다고 해도……!!","JPN":"その先にどんな結末が待っていようとも……！！","ENG":"It doesn't matter what's waiting for me at the other end...!","TWN":"不管最後等待我的結局是什麼……！！"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"결코 후회가 남지 않도록!!","JPN":"決して後悔が残らないように！！","ENG":"I won't have any regrets!!","TWN":"我絕不再留下任何遺憾！！"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"부정. 연합 역시 멸망을 피하기 위해, 동원할 수 있는 모든 연산을 동원했습니다.","JPN":"否定。連合もまた滅亡を避けるために、できる限りの演算を算出しました。","ENG":"Negative. The Interstellar Alliance had also run every possible calculation to avoid devastation.","TWN":"否定。為了避免滅亡，聯盟也動用了一切可以動用的資源。"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"아시모프께서는 유기체가 감당할 수 없는 긴 세월 동안, 그 문제만을 연산하셨습니다.","JPN":"アシモフは有機体が耐えられないほど長い期間、その問題の演算を繰り返しておられました。","ENG":"Asimov had calculated this problem for a time longer than an organism can handle.","TWN":"阿西莫夫在這個問題上花費了相當長的時間，比生物體能夠處理的時間還要長。"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"재차 부정. 엄정하신 기계 장치의 신께서 내린 결론을 부정할 셈입니까?","JPN":"再度否定。厳正なる機械装置の神が下した結論を否定するつもりですか？","ENG":"Double negative. Are you denying the conclusion made by the impartial God of Machinery?","TWN":"再次否認。你要否認公正的機械之神得出的結論嗎？"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그딴 거 내 알 바 아니야!","JPN":"そんなの、アタシの知ったことじゃない。","ENG":"I don't care about that!","TWN":"那不關我的事！"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"세계가 어쩌고, 멸망이 어쩌고, 신이 어쩌고 그딴 와닿지도 않는 이야기! 알 바 아니라고!","JPN":"世界がどうの、滅亡がどうの、神がどうの。そんな話、知ったことじゃないんだよ！","ENG":"All this mumbo-jumbo about the world ending and whatever gods! That's none of my business!","TWN":"世界也好，毀滅也好，還有你們的神也好，這些虛無縹緲的事情！和我有什麼關係！"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"나는 그저 내 앞에서 누군가가 죽지 않길 바랄 뿐이야!","JPN":"アタシはただアタシの目の前で誰かが死ぬところを見たくないだけだ！","ENG":"All I want is for no one to die on my watch!","TWN":"我只希望沒有人死在我面前！"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"너희들이 시험이라는 이유로 죽이려고 했던, 내 소중한 전대원들을 구하고 싶을 뿐이라고!!","JPN":"おまえらが試験という名目で殺そうとした、アタシの大切な戦隊員たちを助けたいだけなんだ！！","ENG":"I just want to save my precious division members that you're trying to kill for your stupid test!","TWN":"我只是想拯救我那些你們以測試為名而試圖殺死的戰隊成員！！"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"만일 당신의 뜻에 따라 제 목숨이 다하게 된다면.","JPN":"神よ、もしもあなたの意志に従い、命の灯火が消えるその時は、","ENG":"And if according to your will I have to lose my life,","TWN":"若是您定意要收回我的性命，"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CAT_IN_TRAILER_7"},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"저의 뜨거운 마지막 순간이 남은 이들을 지켜주는 빛이 될 수 있기를.","JPN":"私の熱い想いが、残された者たちを守る光となるよう、","ENG":"Please help my last moments become a light that protects those who remain.","TWN":"請讓我在生命最後的時刻，"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CAT_IN_TRAILER_8"},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"부디, 허락해주소서.","JPN":"どうか、許し給え。","ENG":"That's all that I ask.","TWN":"能夠燃燒自己成為守護他人的光。"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CAT_IN_TRAILER_9"},{"id":"L7_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"크윽……!!","JPN":"くっ……！！","ENG":"Kgh...!!","TWN":"咳……！！"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"엘부르즈 대검 파손. 물질 재구성까지 36초","JPN":"アルボルズ大剣破損。物質再構成まであと36秒。","ENG":"Alborz greatsword destroyed. Thirty-six seconds until material reconstruction.","TWN":"艾爾布勒茲損壞。距材料重構還需36秒。"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_METAL"},{"id":"L9_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"시무르그 이민선 본체, 대기권 돌입. 대기와의 마찰열로 인해 표면 온도 급상승.","JPN":"シムルグ移民船本体、大気圏突入。大気との摩擦熱により、表面温度急上昇。","ENG":"Simurgh Exodus Fleet, entering the atmosphere. Temperature rapidly rising due to friction heat.","TWN":"西摩格移民船本體進入大氣層。由於與大氣的摩擦，表面溫度迅速升高。"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"경고. 이대로라면 당신도 무사하지 못할 겁니다.","JPN":"警告。このままだと、あなたも無事ではいられません。","ENG":"Warning. You will also not escape unharmed if this continues.","TWN":"警告。再繼續下去，你不可能活著離開這裡。"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"크윽!! 상관없어!!","JPN":"くうっ！！　構わない！！","ENG":"Khhkkk!! I don't care!!","TWN":"呃！！我才不管！！"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그 어떤 화염도 나를 막을 수는 없으니까!!","JPN":"どんな火炎であろうと、アタシを止めることはできない！！","ENG":"No flame can stop me!!","TWN":"任何火焰也阻擋不了我！！"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"한 걸음만 1초만 더 빨랐으면 하는 후회는 이제 지긋지긋해!","JPN":"あと一歩、あと1秒でも早かったならと後悔するのは、もううんざりだ！","ENG":"I've had enough of regretting that I was one step sooner or one second earlier!","TWN":"我已經厭倦總是在來不及的悔恨當中！"},"stage":{"bg":"YAKSHA_02","bgm":null,"filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CAT_IN_TRAILER_10"},{"id":"L16_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이번에야 말로……!","JPN":"今度こそ……！","ENG":"This time...!","TWN":"這一次……！"},"stage":{"bg":"TRAINING","bgm":null,"filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CAT_IN_TRAILER_11"},{"id":"L18_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"목숨이 다하는 한이 있더라도……! 여기서 널 쓰러트리고 모두를 구하겠어!","JPN":"命が尽きようと……！　ここでおまえを倒してみんなを助ける！","ENG":"Even if it costs me my life...! I'll defeat you and save everyone!","TWN":"即便賭上性命……我也要在這裡打倒你拯救大家！"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CAT_IN_TRAILER_12"},{"id":"L19_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"사도 시무르그!","JPN":"使徒シムルグ！","ENG":"Apostle Simurgh!!","TWN":"使徒西摩格！"},"stage":{"bg":"YAKSHA_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_METAL_04","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CAT_IN_TRAILER_13"},{"id":"L22_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"크윽!","JPN":"くうっ！","ENG":"Urgh!","TWN":"咳呃!"},"stage":{"bg":"SPACE_GRAVITY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG"},{"id":"L23_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"무장교체. 시무르그 이민선 본체로부터 무장을 사출.","JPN":"武装交替。シムルグ移民船本体から武装を射出。","ENG":"Switching weapons. Simurgh Exodus Fleet deploying weapon.","TWN":"更換武裝。從西摩格移民船主體中彈出備用裝備。"},"stage":{"bg":"SPACE_GRAVITY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L24_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"프로토콜. 실루엣 체인지.","JPN":"プロトコル。シルエットチェンジ。","ENG":"Protocol. Silhouette Change.","TWN":"協議。更換西摩格之影。"},"stage":{"bg":"SPACE_GRAVITY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"소용없어!!","JPN":"無駄だ！！","ENG":"It's no use!!","TWN":"沒有用的！！"},"stage":{"bg":"SPACE_GRAVITY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"내가 그걸 가만히 보고만 있을 것 같아……!?","JPN":"アタシがそれを黙って見ているとでも思っているのか……！？","ENG":"You think I'm just gonna stand here and do nothing...?!","TWN":"你以為我會看著你這麼做嗎……？"},"stage":{"bg":"SPACE_GRAVITY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"침식 내성이 강한 전대장님이라고 해도 두 번 정도가 한계인 겁니다요.","JPN":"侵食耐性の強い戦隊長だとしても、おそらく2回が限界でやんす。","ENG":"Even if your Corruption resistance is strong, one or two uses would be the limit.","TWN":"即使是耐侵蝕性強大的戰隊長，啟動第二次也已經是極限了。"},"stage":{"bg":"HANGAR","bgm":null,"filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L29_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"꼭 기억하시는 겁니다요! 세 번째는 없습니다요!","JPN":"絶対覚えていてほしいでやんす！　3度目はないでやんす！","ENG":"Remember that! Only use it twice!","TWN":"一定要記住！不能再啟動第三次了！"},"stage":{"bg":"HANGAR","bgm":null,"filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"미안해. 쥐스틴.","JPN":"ごめん。ジュスティーヌ。","ENG":"I'm sorry, Justine.","TWN":"抱歉，潔絲婷。"},"stage":{"bg":"HANGAR","bgm":null,"filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"아무래도 약속은 못 지킬 것 같네.","JPN":"どうやらその約束は、守れそうにない。","ENG":"I don't think I'll be able to keep that promise.","TWN":"我想我可能要食言了。"},"stage":{"bg":"HANGAR","bgm":null,"filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"근데 너도 알고 있잖냐? 내 성격.","JPN":"でも、おまえも知ってるだろう？　アタシの性格。","ENG":"But you know what I'm like.","TWN":"但你也知道吧？我的性格。"},"stage":{"bg":"HANGAR","bgm":null,"filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"난 말이야. 남들이 하지 말라고 말리면, 오히려 해봐야 직성이 풀린다고?","JPN":"アタシはな。人がやるなって止めると、むしろやってみないと気が済まないんだよ。","ENG":"I'm the type who finds satisfaction in doing the complete opposite of what others tell me not to do.","TWN":"我這個人啊。別人不讓我做什麼，我就非要做什麼才甘心呢？"},"stage":{"bg":"HANGAR","bgm":null,"filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"그 대신 반드시 이길게.","JPN":"その代わり、必ず勝ってみせる。","ENG":"Instead, I'll win no matter what.","TWN":"不過我一定會勝利的。"},"stage":{"bg":"HANGAR","bgm":null,"filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"반드시 이겨서 모두를 구할 테니까.","JPN":"必ず勝って、みんなを助けるから。","ENG":"I'll win and save everyone.","TWN":"我一定會勝利，拯救大家的。"},"stage":{"bg":"HANGAR","bgm":null,"filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"아스트라 드라이브. 기동!","JPN":"アストラ・ドライブ。起動！","ENG":"Astra Drive activated!","TWN":"艾斯特拉引擎。啟動！"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};